import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// --- ICONS ---
const Icons = {
  Add: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" /></svg>),
  Trash: () => (<svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M14.74 9l-.346 9m-4.788 0L9.26 9m9.968-3.21c.342.052.682.107 1.022.166m-1.022-.165L18.16 19.673a2.25 2.25 0 01-2.244 2.077H8.084a2.25 2.25 0 01-2.244-2.077L4.772 5.79m14.456 0a48.108 48.108 0 00-3.478-.397m-12 .562c.34-.059.68-.114 1.022-.165m0 0a48.11 48.11 0 013.478-.397m7.5 0v-.916c0-1.18-.91-2.164-2.09-2.201a51.964 51.964 0 00-3.32 0c-1.18.037-2.09 1.022-2.09 2.201v.916m7.5 0a48.667 48.667 0 00-7.5 0" /></svg>)
};

const DisciplineManager = () => {
  const { user } = useAuth();
  // Bổ sung hàm updateDiscipline từ DataContext
  const { disciplineTypes, staffList, addDiscipline, deleteDiscipline, updateDiscipline, addDisciplineRecord, deleteDisciplineRecord, disciplines } = useData();

  // Phân quyền
  const isOp = user?.role === 'op';
  const isReg = user?.role === 'reg';
  const isChief = user?.role === 'chief';

  const [newDiscipline, setNewDiscipline] = useState({ name: '', type: 'Chuyên môn', points: '' });
  const [newRecord, setNewRecord] = useState({ staffId: '', disciplineTypeId: '', reason: '', date: '' });

  // --- LOGIC: THÊM / ĐỀ XUẤT HÌNH THỨC KỶ LUẬT ---
  const handleAddDiscipline = (e) => {
    e.preventDefault();
    if (!newDiscipline.name || !newDiscipline.points) return;
    
    // OP tạo sẽ mang trạng thái pending. REG/CHIEF tạo sẽ là Active
    const payload = {
        ...newDiscipline,
        points: Number(newDiscipline.points),
        status: isOp ? 'pending' : 'Active',
        proposedBy: isOp ? user.username : null,
        deleteRequested: false,
        deleteReason: null
    };

    addDiscipline(payload);
    setNewDiscipline({ name: '', type: 'Chuyên môn', points: '' });
    alert(isOp ? "Đã gửi đề xuất hình thức kỷ luật chờ duyệt!" : "Đã ban hành hình thức kỷ luật mới!");
  };

  // --- LOGIC: REG ĐỀ XUẤT XÓA ---
  const handleRequestDelete = (d) => {
      const reason = window.prompt("Vui lòng nhập lý do đề xuất xóa hình thức này:");
      if (reason && reason.trim() !== "") {
          updateDiscipline(d.id, { deleteRequested: true, deleteReason: reason });
          alert("Đã gửi đề xuất xóa lên Chief Admin!");
      }
  };

  // --- LOGIC: GHI NHẬN VI PHẠM ---
  const handleAddRecord = (e) => {
    e.preventDefault();
    if (!newRecord.staffId || !newRecord.disciplineTypeId || !newRecord.date) return;

    const staff = staffList.find(s => s.id === newRecord.staffId);
    const type = disciplineTypes.find(d => d.id === newRecord.disciplineTypeId);

    addDisciplineRecord({
        staffId: staff.id,
        staffName: staff.name,
        typeId: type.id,
        typeName: type.name,
        points: type.points,
        reason: newRecord.reason,
        date: new Date(newRecord.date).toISOString()
    });

    setNewRecord({ staffId: '', disciplineTypeId: '', reason: '', date: '' });
    alert("Đã ghi nhận vi phạm!");
  };

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #e5e7eb', paddingBottom: '15px', marginBottom: '20px', fontWeight: 'bold', fontSize: '1.5rem' }}>
        Quản lý Kỷ luật
      </h2>

      {/* =========================================================
          MỤC 1: DANH MỤC HÌNH THỨC KỶ LUẬT
      ========================================================= */}
      <div style={{ marginBottom: '40px' }}>
          <h3 style={{ color: '#003366', fontSize: '1.2rem', marginBottom: '15px' }}>1. Danh mục hình thức kỷ luật (Hiện hành)</h3>
          
          {/* Form Tạo / Đề xuất */}
          <div style={styles.card}>
              <h4 style={{ margin: '0 0 15px 0', color: '#1f2937' }}>
                  {isOp ? 'Đề xuất hình thức kỷ luật mới' : 'Ban hành hình thức kỷ luật mới'}
              </h4>
              <form onSubmit={handleAddDiscipline} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', alignItems: 'center' }}>
                  <input placeholder="Tên hình thức (VD: Đi trễ, Thái độ...)" value={newDiscipline.name} onChange={e => setNewDiscipline({...newDiscipline, name: e.target.value})} style={{...styles.input, flex: '1 1 200px'}} required />
                  <select value={newDiscipline.type} onChange={e => setNewDiscipline({...newDiscipline, type: e.target.value})} style={styles.select}>
                      <option value="Chuyên môn">Chuyên môn</option>
                      <option value="Thái độ">Thái độ</option>
                      <option value="Vi phạm nội quy">Vi phạm nội quy</option>
                  </select>
                  <input type="number" placeholder="Điểm trừ" value={newDiscipline.points} onChange={e => setNewDiscipline({...newDiscipline, points: e.target.value})} style={{...styles.input, width: '100px'}} required />
                  <button type="submit" style={styles.btnAdd}>
                      <Icons.Add /> {isOp ? 'Gửi đề xuất' : 'Thêm mới'}
                  </button>
              </form>
          </div>

          {/* Bảng Danh sách Hình thức */}
          <div style={{ ...styles.card, marginTop: '20px' }}>
              <div style={{ overflowX: 'auto' }}>
                  <table style={styles.table}>
                      <thead>
                          <tr style={{ background: '#f9fafb', color: '#4b5563', textAlign: 'left', borderBottom: '2px solid #e5e7eb' }}>
                              <th style={{ padding: '12px' }}>Hình thức vi phạm</th>
                              <th style={{ padding: '12px' }}>Nhóm</th>
                              <th style={{ padding: '12px' }}>Điểm trừ</th>
                              <th style={{ padding: '12px' }}>Tình trạng / Đề xuất</th>
                              <th style={{ padding: '12px' }}>Hành động</th>
                          </tr>
                      </thead>
                      <tbody>
                          {disciplineTypes.map(d => {
                              const isPending = d.status === 'pending';
                              const isSuspended = d.status === 'suspended';
                              const isActive = d.status === 'Active' || !d.status;
                              const isDeleteRequested = d.deleteRequested;

                              return (
                                  <tr key={d.id} style={{ borderBottom: '1px solid #f3f4f6', background: isDeleteRequested ? '#fefce8' : 'transparent' }}>
                                      <td style={{ padding: '12px', fontWeight: '600', color: '#111827' }}>{d.name}</td>
                                      <td style={{ padding: '12px', color: '#4b5563' }}>{d.type}</td>
                                      <td style={{ padding: '12px', color: '#dc2626', fontWeight: 'bold' }}>-{d.points} đ</td>
                                      
                                      {/* Cột Tình trạng */}
                                      <td style={{ padding: '12px' }}>
                                          {isPending && <span style={styles.badgePending}>Chờ duyệt (OP Đề xuất)</span>}
                                          {isSuspended && <span style={styles.badgeError}>Đình chỉ</span>}
                                          {isActive && !isDeleteRequested && <span style={styles.badgeSuccess}>Đã duyệt</span>}
                                          {isDeleteRequested && (
                                              <div style={{ marginTop: '4px' }}>
                                                  <span style={styles.badgeWarning}>⏳ Xin xóa: {d.deleteReason}</span>
                                              </div>
                                          )}
                                      </td>

                                      {/* Cột Hành động theo Phân quyền */}
                                      <td style={{ padding: '12px' }}>
                                          {/* Quyền REG xử lý đề xuất từ OP */}
                                          {isReg && isPending && (
                                              <div style={{ display: 'flex', gap: '8px' }}>
                                                  <button onClick={() => updateDiscipline(d.id, {status: 'Active'})} style={styles.btnApprove}>Duyệt</button>
                                                  <button onClick={() => updateDiscipline(d.id, {status: 'suspended'})} style={styles.btnReject}>Đình chỉ</button>
                                              </div>
                                          )}
                                          
                                          {/* Quyền REG đề xuất Xóa */}
                                          {isReg && isActive && !isDeleteRequested && (
                                              <button onClick={() => handleRequestDelete(d)} style={styles.btnWarningSmall}>Đề xuất xóa</button>
                                          )}

                                          {/* Quyền CHIEF xử lý đề xuất xóa từ REG */}
                                          {isChief && isDeleteRequested && (
                                              <div style={{ display: 'flex', gap: '8px' }}>
                                                  <button onClick={() => deleteDiscipline(d.id)} style={styles.btnReject}>Duyệt Xóa</button>
                                                  <button onClick={() => updateDiscipline(d.id, {deleteRequested: false, deleteReason: null})} style={styles.btnApprove}>Từ chối Xóa</button>
                                              </div>
                                          )}
                                      </td>
                                  </tr>
                              );
                          })}
                          {disciplineTypes.length === 0 && <tr><td colSpan="5" style={{ padding: '20px', textAlign: 'center', color: '#9ca3af' }}>Chưa có dữ liệu.</td></tr>}
                      </tbody>
                  </table>
              </div>
          </div>
      </div>

      {/* =========================================================
          MỤC 2: HỒ SƠ NHÂN SỰ VI PHẠM
      ========================================================= */}
      <div>
          <h3 style={{ color: '#003366', fontSize: '1.2rem', marginBottom: '15px' }}>2. Hồ sơ nhân sự vi phạm</h3>
          
          {/* Form Ghi nhận vi phạm */}
          <div style={styles.card}>
              <h4 style={{ margin: '0 0 15px 0', color: '#1f2937' }}>Ghi nhận vi phạm mới</h4>
              <form onSubmit={handleAddRecord} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
                  <select value={newRecord.staffId} onChange={e => setNewRecord({...newRecord, staffId: e.target.value})} style={styles.select} required>
                      <option value="">-- Chọn nhân sự --</option>
                      {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>

                  <select value={newRecord.disciplineTypeId} onChange={e => setNewRecord({...newRecord, disciplineTypeId: e.target.value})} style={styles.select} required>
                      <option value="">-- Hình thức vi phạm --</option>
                      {disciplineTypes.filter(d => d.status === 'Active' && !d.deleteRequested).map(d => (
                          <option key={d.id} value={d.id}>{d.name} (-{d.points}đ)</option>
                      ))}
                  </select>

                  <input type="date" value={newRecord.date} onChange={e => setNewRecord({...newRecord, date: e.target.value})} style={styles.input} required />
                  <input placeholder="Lý do / Mô tả chi tiết..." value={newRecord.reason} onChange={e => setNewRecord({...newRecord, reason: e.target.value})} style={styles.input} />

                  <button type="submit" style={{...styles.btnAdd, gridColumn: '1 / -1', justifyContent: 'center', padding: '12px'}}>
                      Lưu Hồ Sơ
                  </button>
              </form>
          </div>

          {/* Bảng Danh sách Hồ sơ vi phạm */}
          <div style={{ ...styles.card, marginTop: '20px' }}>
              <div style={{ overflowX: 'auto' }}>
                  <table style={styles.table}>
                      <thead>
                          <tr style={{ background: '#fef2f2', color: '#991b1b', textAlign: 'left', borderBottom: '2px solid #fecaca' }}>
                              <th style={{ padding: '12px' }}>Thời gian</th>
                              <th style={{ padding: '12px' }}>Nhân sự</th>
                              <th style={{ padding: '12px' }}>Lỗi vi phạm</th>
                              <th style={{ padding: '12px' }}>Chi tiết</th>
                              <th style={{ padding: '12px' }}>Điểm trừ</th>
                              <th style={{ padding: '12px' }}>Xóa</th>
                          </tr>
                      </thead>
                      <tbody>
                          {disciplines.sort((a,b) => new Date(b.date) - new Date(a.date)).map(r => (
                              <tr key={r.id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                                  <td style={{ padding: '12px', color: '#4b5563' }}>{new Date(r.date).toLocaleDateString('vi-VN')}</td>
                                  <td style={{ padding: '12px', fontWeight: '600' }}>{r.staffName}</td>
                                  <td style={{ padding: '12px' }}>{r.typeName}</td>
                                  <td style={{ padding: '12px', color: '#6b7280', fontSize: '0.85rem' }}>{r.reason || '---'}</td>
                                  <td style={{ padding: '12px', color: '#dc2626', fontWeight: 'bold' }}>-{r.points}</td>
                                  <td style={{ padding: '12px' }}>
                                      <button onClick={() => { if(window.confirm('Xóa bản ghi vi phạm này?')) deleteDisciplineRecord(r.id) }} style={styles.btnIconRed}>
                                          <Icons.Trash />
                                      </button>
                                  </td>
                              </tr>
                          ))}
                          {disciplines.length === 0 && <tr><td colSpan="6" style={{ padding: '20px', textAlign: 'center', color: '#9ca3af' }}>Chưa có hồ sơ vi phạm.</td></tr>}
                      </tbody>
                  </table>
              </div>
          </div>
      </div>
    </div>
  );
};

